import { describe, expect, it } from "vitest";
import { readFileSync } from "node:fs";
import { resolve } from "node:path";

// vitest runs with root = docs/site; cwd-relative resolution is stable across
// direct invocation and the full suite (import.meta.url gets mangled by the
// happy-dom transform in the latter).
const content = (p: string) =>
  JSON.parse(readFileSync(resolve(process.cwd(), "content", "docs", p), "utf8"));

/**
 * Guards the sidebar information architecture:
 * - every top-level content dir is explicitly placed (no floating auto-append)
 * - the 192-page reference tree stays a root tab, out of the main sidebar
 * - big generated folders stay collapsed by default
 */
describe("sidebar IA structure", () => {
  it("root meta places every non-root content section explicitly", () => {
    const pages: string[] = content("meta.json").pages;
    // Sections are placed as collapsible folder refs ("foundations") — the
    // spread form ("...foundations") is also accepted for back-compat. Both
    // "explicitly place" the section; separators ("---…---") are ignored.
    const placed = pages
      .filter((p) => !p.startsWith("---"))
      .map((p) => (p.startsWith("...") ? p.slice(3) : p));
    for (const section of [
      "getting-started",
      "foundations",
      "memory",
      "analytics",
      "skills",
      "agents",
      "hooks",
      "guides",
      "cookbook",
      "showcase",
      "troubleshooting",
      "changelog",
    ]) {
      expect(placed, `${section} must be explicitly placed in root meta.json`).toContain(section);
    }
    // reference is deliberately NOT in the main tree — it is its own root tab
    expect(placed).not.toContain("reference");
  });

  it("reference is a root tab with collapsed generated folders", () => {
    expect(content("reference/meta.json").root).toBe(true);
    for (const sub of ["skills", "agents", "hooks"]) {
      expect(
        content(`reference/${sub}/meta.json`).defaultOpen,
        `reference/${sub} must default to collapsed`,
      ).toBe(false);
    }
  });
});
